// Impure — mutates input
function addTodoBad(todos, text) {
  todos.push({ id: Date.now(), text, done: false });
  return todos;
}

// Pure — returns new array
function addTodoPure(todos, text) {
  return [...todos, { id: Date.now(), text, done: false }];
}

export interface Todo {
  id: string;
  text: string;
  completed: boolean;
}

export type Filter = 'all' | 'active' | 'completed';

export interface TodosState {
  items: Todo[];
  filter: Filter;
}

const initialState: TodosState = { items: [], filter: 'all' };

import { configureStore } from '@reduxjs/toolkit';
import todosReducer from '../features/todos/todosSlice';

export const store = configureStore({
  reducer: { todos: todosReducer },
});

export type RootState = ReturnType<typeof store.getState>;
export type AppDispatch = typeof store.dispatch;

const todosSlice = createSlice({
  name: 'todos',
  initialState,
  reducers: {
    addTodo(state, action: PayloadAction<string>) {
      state.items.push({ id: crypto.randomUUID(), text: action.payload, completed: false });
    },
    toggleTodo(state, action: PayloadAction<string>) {
      const todo = state.items.find(t => t.id === action.payload);
      if (todo) todo.completed = !todo.completed;
    },
  },
});

export const selectFilteredTodos = (state: RootState) => {
  const { items, filter } = state.todos;
  if (filter === 'active') return items.filter(t => !t.completed);
  if (filter === 'completed') return items.filter(t => t.completed);
  return items;
};
